import{_ as n,c as t,o as i,a1 as a}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"OpenAI-Kredit: 3h/24h Abfrage | opencode-mystatus","description":"Lernen Sie die OpenAI-Kreditabfrage für 3-Stunden- und 24-Stunden-Fenster. Verstehen Sie Rate-Limits, Haupt- und Nebenfenster, Plus/Team/Pro-Unterschiede und lösen Token-Ablaufprobleme.","frontmatter":{"title":"OpenAI-Kredit: 3h/24h Abfrage | opencode-mystatus","sidebarTitle":"OpenAI-Kredit","subtitle":"OpenAI-Kredit: 3h/24h Abfrage","description":"Lernen Sie die OpenAI-Kreditabfrage für 3-Stunden- und 24-Stunden-Fenster. Verstehen Sie Rate-Limits, Haupt- und Nebenfenster, Plus/Team/Pro-Unterschiede und lösen Token-Ablaufprobleme.","tags":["OpenAI","Kreditabfrage","API-Quote"],"prerequisite":["start-quick-start","start-understanding-output"],"order":1},"headers":[],"relativePath":"de/vbgate/opencode-mystatus/platforms/openai-usage/index.md","filePath":"de/vbgate/opencode-mystatus/platforms/openai-usage/index.md"}'),r={name:"de/vbgate/opencode-mystatus/platforms/openai-usage/index.md"};function s(l,e,o,d,u,h){return i(),t("div",null,[...e[0]||(e[0]=[a(`<h1 id="openai-kreditabfrage-3-stunden-und-24-stunden-kredite" tabindex="-1">OpenAI-Kreditabfrage: 3-Stunden- und 24-Stunden-Kredite <a class="header-anchor" href="#openai-kreditabfrage-3-stunden-und-24-stunden-kredite" aria-label="Permalink to &quot;OpenAI-Kreditabfrage: 3-Stunden- und 24-Stunden-Kredite&quot;">​</a></h1><h2 id="was-sie-nach-diesem-tutorial-konnen" tabindex="-1">Was Sie nach diesem Tutorial können <a class="header-anchor" href="#was-sie-nach-diesem-tutorial-konnen" aria-label="Permalink to &quot;Was Sie nach diesem Tutorial können&quot;">​</a></h2><ul><li>Verwenden Sie <code>/mystatus</code>, um Kredite von OpenAI Plus/Team/Pro-Abonnements abzufragen</li><li>Verstehen Sie die Informationen zu 3-Stunden- und 24-Stunden-Krediten in der Ausgabe</li><li>Verstehen Sie den Unterschied zwischen Haupt- und Nebenfenstern</li><li>Erfahren Sie, wie Token-Ablauf behandelt wird</li></ul><h2 id="ihre-aktuelle-situation" tabindex="-1">Ihre aktuelle Situation <a class="header-anchor" href="#ihre-aktuelle-situation" aria-label="Permalink to &quot;Ihre aktuelle Situation&quot;">​</a></h2><p>Die OpenAI-API-Aufrufe sind begrenzt. Nach Überschreitung werden Sie temporär eingeschränkt. Aber Sie wissen nicht:</p><ul><li>Wie viel Kredit verbleibt aktuell?</li><li>Welches der 3-Stunden- und 24-Stunden-Fenster wird verwendet?</li><li>Wann wird zurückgesetzt?</li><li>Warum werden manchmal Daten aus zwei Fenstern angezeigt?</li></ul><p>Wenn Sie diese Informationen nicht rechtzeitig kennen, kann dies Ihren Fortschritt bei der Entwicklung mit ChatGPT beeinträchtigen.</p><h2 id="wann-sollten-sie-dies-verwenden" tabindex="-1">Wann sollten Sie dies verwenden? <a class="header-anchor" href="#wann-sollten-sie-dies-verwenden" aria-label="Permalink to &quot;Wann sollten Sie dies verwenden?&quot;">​</a></h2><p>Wenn Sie:</p><ul><li>Häufig OpenAI-API zur Entwicklung verwenden</li><li>Langsamere Antworten oder Rate-Limiting bemerken</li><li>Die Nutzung von Teamkonten erfahren möchten</li><li>Wann der Kredit zurückgesetzt wird, wissen möchten</li></ul><h2 id="grundlegende-idee" tabindex="-1">Grundlegende Idee <a class="header-anchor" href="#grundlegende-idee" aria-label="Permalink to &quot;Grundlegende Idee&quot;">​</a></h2><p>OpenAI hat zwei Rate-Limiting-Fenster für API-Aufrufe:</p><table tabindex="0"><thead><tr><th>Fenstertyp</th><th>Dauer</th><th>Funktion</th></tr></thead><tbody><tr><td><strong>Hauptfenster</strong> (primary)</td><td>Wird vom OpenAI-Server zurückgegeben</td><td>Verhindert zahlreiche Aufrufe in kurzer Zeit</td></tr><tr><td><strong>Nebenfenster</strong> (secondary)</td><td>Wird vom OpenAI-Server zurückgegeben (kann fehlen)</td><td>Verhindert langfristige Übernutzung</td></tr></tbody></table><p>mystatus fragt beide Fenster parallel ab und zeigt für jedes:</p><ul><li>Verwendeten Prozentsatz</li><li>Verbleibenden Kredit-Fortschrittsbalken</li><li>Zeit bis zur Rücksetzung</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Die Fensterausführungszeit wird vom OpenAI-Server zurückgegeben und kann für verschiedene Abonnementtypen (Plus, Team, Pro) unterschiedlich sein.</p></div><h2 id="folgen-sie-mir" tabindex="-1">Folgen Sie mir <a class="header-anchor" href="#folgen-sie-mir" aria-label="Permalink to &quot;Folgen Sie mir&quot;">​</a></h2><h3 id="schritt-1-abfragebefehl-ausfuhren" tabindex="-1">Schritt 1: Abfragebefehl ausführen <a class="header-anchor" href="#schritt-1-abfragebefehl-ausfuhren" aria-label="Permalink to &quot;Schritt 1: Abfragebefehl ausführen&quot;">​</a></h3><p>Geben Sie in OpenCode <code>/mystatus</code> ein, das System fragt automatisch die Kreditinformationen aller konfigurierten Plattformen ab.</p><p><strong>Was Sie sehen sollten</strong>: Enthält Kreditinformationen von Plattformen wie OpenAI, Zhipu AI, Z.ai, Copilot, Google Cloud (abhängig davon, welche Plattformen Sie konfiguriert haben).</p><h3 id="schritt-2-openai-abschnitt-finden" tabindex="-1">Schritt 2: OpenAI-Abschnitt finden <a class="header-anchor" href="#schritt-2-openai-abschnitt-finden" aria-label="Permalink to &quot;Schritt 2: OpenAI-Abschnitt finden&quot;">​</a></h3><p>Suchen Sie in der Ausgabe den Abschnitt <code>## OpenAI Account Quota</code>.</p><p><strong>Was Sie sehen sollten</strong>: Ähnlich diesem Inhalt:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## OpenAI Account Quota</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Account:        user@example.com (plus)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3-hour limit</span></span>
<span class="line"><span>██████████████████░░░░░░░░ 60% remaining</span></span>
<span class="line"><span>Resets in: 2h 30m</span></span></code></pre></div><h3 id="schritt-3-hauptfenster-informationen-interpretieren" tabindex="-1">Schritt 3: Hauptfenster-Informationen interpretieren <a class="header-anchor" href="#schritt-3-hauptfenster-informationen-interpretieren" aria-label="Permalink to &quot;Schritt 3: Hauptfenster-Informationen interpretieren&quot;">​</a></h3><p>Das <strong>Hauptfenster</strong> (primary_window) zeigt normalerweise:</p><ul><li><strong>Fenstername</strong>: Wie <code>3-hour limit</code> oder <code>24-hour limit</code></li><li><strong>Fortschrittsbalken</strong>: Visuelle Darstellung des verbleibenden Kreditanteils</li><li><strong>Verbleibender Prozentsatz</strong>: Wie <code>60% remaining</code></li><li><strong>Rücksetzzeit</strong>: Wie <code>Resets in: 2h 30m</code></li></ul><p><strong>Was Sie sehen sollten</strong>:</p><ul><li>Der Fenstername zeigt die Dauer (3 Stunden / 24 Stunden)</li><li>Je voller der Fortschrittsbalken, desto mehr verbleibt, je leerer, desto schneller wird er aufgebraucht</li><li>Die Rücksetzzeit ist ein Countdown, bei Null wird der Kredit aktualisiert</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Wenn Sie <code>Limit reached!</code> sehen, ist der aktuelle Kredit aufgebraucht, Sie müssen auf die Rücksetzung warten.</p></div><h3 id="schritt-4-nebenfenster-anzeigen-falls-vorhanden" tabindex="-1">Schritt 4: Nebenfenster anzeigen (falls vorhanden) <a class="header-anchor" href="#schritt-4-nebenfenster-anzeigen-falls-vorhanden" aria-label="Permalink to &quot;Schritt 4: Nebenfenster anzeigen (falls vorhanden)&quot;">​</a></h3><p>Wenn OpenAI Daten des Nebenfensters zurückgibt, sehen Sie:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>24-hour limit</span></span>
<span class="line"><span>████████████████████████████ 90% remaining</span></span>
<span class="line"><span>Resets in: 20h 45m</span></span></code></pre></div><p><strong>Was Sie sehen sollten</strong>:</p><ul><li>Das Nebenfenster zeigt eine andere Zeitdimension der Kreditnutzung (normalerweise 24 Stunden)</li><li>Kann einen anderen verbleibenden Prozentsatz haben als das Hauptfenster</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Das Nebenfenster ist ein unabhängiger Kredit-Pool. Wenn das Hauptfenster aufgebraucht ist, wird das Nebenfenster nicht beeinträchtigt und umgekehrt.</p></div><h3 id="schritt-5-abonnementtyp-anzeigen" tabindex="-1">Schritt 5: Abonnementtyp anzeigen <a class="header-anchor" href="#schritt-5-abonnementtyp-anzeigen" aria-label="Permalink to &quot;Schritt 5: Abonnementtyp anzeigen&quot;">​</a></h3><p>In der <code>Account</code>-Zeile können Sie den Abonnementtyp sehen:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Account:        user@example.com (plus)</span></span>
<span class="line"><span>                                   ^^^^^</span></span>
<span class="line"><span>                                   Abonnementtyp</span></span></code></pre></div><p><strong>Häufige Abonnementtypen</strong>:</p><ul><li><code>plus</code>: Persönliches Plus-Abonnement</li><li><code>team</code>: Team-/Organisationsabonnement</li><li><code>pro</code>: Pro-Abonnement</li></ul><p><strong>Was Sie sehen sollten</strong>:</p><ul><li>Ihr Kontotyp wird in Klammern nach der E-Mail angezeigt</li><li>Unterschiedliche Typen können unterschiedliche Kreditbeschränkungen haben</li></ul><h2 id="kontrollpunkt-✅" tabindex="-1">Kontrollpunkt ✅ <a class="header-anchor" href="#kontrollpunkt-✅" aria-label="Permalink to &quot;Kontrollpunkt ✅&quot;">​</a></h2><p>Überprüfen Sie, dass Sie Folgendes verstehen:</p><table tabindex="0"><thead><tr><th>Szenario</th><th>Was Sie sehen sollten</th></tr></thead><tbody><tr><td>Hauptfenster verbleibend 60%</td><td>Fortschrittsbalken ca. 60% voll, zeigt <code>60% remaining</code></td></tr><tr><td>Rücksetzung nach 2,5 Stunden</td><td>Zeigt <code>Resets in: 2h 30m</code></td></tr><tr><td>Limit erreicht</td><td>Zeigt <code>Limit reached!</code></td></tr><tr><td>Nebenfenster vorhanden</td><td>Haupt- und Nebenfenster haben jeweils eine Zeile Daten</td></tr></tbody></table><h2 id="haufige-fehler" tabindex="-1">Häufige Fehler <a class="header-anchor" href="#haufige-fehler" aria-label="Permalink to &quot;Häufige Fehler&quot;">​</a></h2><h3 id="❌-falsche-operation-nicht-nach-token-ablauf-aktualisieren" tabindex="-1">❌ Falsche Operation: Nicht nach Token-Ablauf aktualisieren <a class="header-anchor" href="#❌-falsche-operation-nicht-nach-token-ablauf-aktualisieren" aria-label="Permalink to &quot;❌ Falsche Operation: Nicht nach Token-Ablauf aktualisieren&quot;">​</a></h3><p><strong>Fehlererscheinung</strong>: Sie sehen <code>⚠️ OAuth-Autorisierung abgelaufen</code> (Chinesisch) oder <code>⚠️ OAuth token expired</code> (Englisch)</p><p><strong>Ursache</strong>: Der OAuth-Token ist abgelaufen (bestimmte Dauer vom Server gesteuert), nach Ablauf kann der Kredit nicht abgefragt werden.</p><p><strong>Richtige Operation</strong>:</p><ol><li>Melden Sie sich in OpenCode erneut bei OpenAI an</li><li>Der Token wird automatisch aktualisiert</li><li>Führen Sie <code>/mystatus</code> erneut aus, um abzufragen</li></ol><h3 id="❌-falsche-operation-haupt-und-nebenfenster-verwechseln" tabindex="-1">❌ Falsche Operation: Haupt- und Nebenfenster verwechseln <a class="header-anchor" href="#❌-falsche-operation-haupt-und-nebenfenster-verwechseln" aria-label="Permalink to &quot;❌ Falsche Operation: Haupt- und Nebenfenster verwechseln&quot;">​</a></h3><p><strong>Fehlererscheinung</strong>: Sie denken, es gibt nur ein Kreditfenster, aber das Hauptfenster ist aufgebraucht und das Nebenfenster wird weiterhin verwendet</p><p><strong>Ursache</strong>: Die beiden Fenster sind unabhängige Kredit-Pools.</p><p><strong>Richtige Operation</strong>:</p><ul><li>Achten Sie auf die Rücksetzzeit beider Fenster</li><li>Hauptfenster setzt schneller zurück, Nebenfenster langsamer</li><li>Ordnen Sie die Verwendung angemessen zu, vermeiden Sie, dass ein Fenster langfristig überlastet ist</li></ul><h3 id="❌-falsche-operation-teamkonto-id-ignorieren" tabindex="-1">❌ Falsche Operation: Teamkonto-ID ignorieren <a class="header-anchor" href="#❌-falsche-operation-teamkonto-id-ignorieren" aria-label="Permalink to &quot;❌ Falsche Operation: Teamkonto-ID ignorieren&quot;">​</a></h3><p><strong>Fehlererscheinung</strong>: Team-Abonnement zeigt nicht Ihre eigene Nutzung</p><p><strong>Ursache</strong>: Team-Abonnement muss die Teamkonto-ID übergeben, andernfalls wird möglicherweise das Standardkonto abgefragt.</p><p><strong>Richtige Operation</strong>:</p><ul><li>Stellen Sie sicher, dass Sie das richtige Teamkonto in OpenCode angemeldet haben</li><li>Der Token enthält automatisch <code>chatgpt_account_id</code></li></ul><h2 id="zusammenfassung" tabindex="-1">Zusammenfassung <a class="header-anchor" href="#zusammenfassung" aria-label="Permalink to &quot;Zusammenfassung&quot;">​</a></h2><p>mystatus fragt Kredite ab, indem es die offizielle OpenAI-API aufruft:</p><ul><li>Unterstützt OAuth-Authentifizierung (Plus/Team/Pro)</li><li>Zeigt Haupt- und Nebenfenster (falls vorhanden)</li><li>Visualisiert verbleibenden Kredit mit Fortschrittsbalken</li><li>Countdown zeigt Rücksetzzeit</li><li>Erkennung von Token-Ablauf automatisch</li></ul><h2 id="vorschau-auf-die-nachste-lektion" tabindex="-1">Vorschau auf die nächste Lektion <a class="header-anchor" href="#vorschau-auf-die-nachste-lektion" aria-label="Permalink to &quot;Vorschau auf die nächste Lektion&quot;">​</a></h2><blockquote><p>In der nächsten Lektion lernen wir <strong><a href="./../zhipu-usage/">Zhipu AI und Z.ai-Kreditabfrage</a></strong>.</p><p>Sie werden lernen:</p><ul><li>Was ist der 5-Stunden-Token-Kredit</li><li>Wie man die MCP-monatliche Quote anzeigt</li><li>Warnhinweise, wenn die Nutzung 80% überschreitet</li></ul></blockquote><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken Sie hier, um die Quellcodepositionen anzuzeigen</strong></summary><blockquote><p>Aktualisierungszeit: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilennummer</th></tr></thead><tbody><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Ausgabe formatieren</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L164-L194" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>164-194</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>OpenAIAuthData Typdefinition</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/types.ts#L28-L33" target="_blank" rel="noreferrer"><code>plugin/lib/types.ts</code></a></td><td>28-33</td></tr></tbody></table><p><strong>Konstanten</strong>:</p><ul><li><code>OPENAI_USAGE_URL = &quot;https://chatgpt.com/backend-api/wham/usage&quot;</code>: Offizielle OpenAI-Kreditabfrage-API</li></ul><p><strong>Wichtige Funktionen</strong>:</p><ul><li><code>queryOpenAIUsage(authData)</code>: Hauptfunktion zum Abfragen von OpenAI-Krediten</li><li><code>fetchOpenAIUsage(accessToken)</code>: Ruft OpenAI-API auf</li><li><code>formatOpenAIUsage(data, email)</code>: Formatiert Ausgabe</li><li><code>parseJwt(token)</code>: Analysiert JWT-Token (keine Standardbibliothek)</li><li><code>getEmailFromJwt(token)</code>: Extrahiert Benutzer-E-Mail aus Token</li><li><code>getAccountIdFromJwt(token)</code>: Extrahiert Teamkonto-ID aus Token</li></ul></details>`,70)])])}const g=n(r,[["render",s]]);export{p as __pageData,g as default};
